ee:variables.ee:set-variable:
%dw 2.0
output application/java
var e = vars.estadoRows[0]

var temp0 = e.temperatura_actual as Number
var light0 = e.iluminacion_actual as Number
var hvacMode = (e.hvac_mode default "IDLE") as String
var lightMode = (e.light_mode default "IDLE") as String
var hvacTarget = e.hvac_target
var lightTarget = e.light_target
var ciclos0 = (e.ciclos_estables default 0) as Number
var indice0 = (e.indice_perturbacion default 0) as Number

// 1) Evolución normal si hay modos activos
var tempBase =
  if (hvacMode == "COOLING" and hvacTarget != null)
    if (temp0 - 0.5 < (hvacTarget as Number))
      hvacTarget as Number
    else
      temp0 - 0.5
  else if (hvacMode == "HEATING" and hvacTarget != null)
    if (temp0 + 0.5 > (hvacTarget as Number))
      hvacTarget as Number
    else
      temp0 + 0.5
  else
    temp0

var lightBase =
  if (lightMode == "DIMMING" and lightTarget != null)
    if (light0 - 50 < (lightTarget as Number))
      lightTarget as Number
    else
      light0 - 50
  else if (lightMode == "BRIGHTENING" and lightTarget != null)
    if (light0 + 50 > (lightTarget as Number))
      lightTarget as Number
    else
      light0 + 50
  else
    light0

// 2) Oficina completamente estable
var ambosIdle = (hvacMode == "IDLE") and (lightMode == "IDLE")
var enConfort =
  (tempBase >= 23 and tempBase <= 25) and
  (lightBase >= 450 and lightBase <= 650)

// 3) Contador de estabilidad
var ciclos1 =
  if (ambosIdle and enConfort)
    ciclos0 + 1
  else
    0

// 4) Disparo de perturbación tras 2 ciclos estables
var dispararPerturbacion =
  ambosIdle and enConfort and ciclos1 >= 2

// 5) Selector persistido
var selector = indice0 mod 8

// 6) Aplicar perturbación controlada
var tempFinal =
  if (!dispararPerturbacion)
    tempBase
  else if (selector == 0 or selector == 4 or selector == 5)
    27.0
  else if (selector == 1 or selector == 6 or selector == 7)
    21.0
  else
    tempBase

var lightFinal =
  if (!dispararPerturbacion)
    lightBase
  else if (selector == 2 or selector == 4 or selector == 6)
    800.0
  else if (selector == 3 or selector == 5 or selector == 7)
    350.0
  else
    lightBase

var ciclosFinal =
  if (dispararPerturbacion)
    0
  else
    ciclos1

var indiceFinal =
  if (dispararPerturbacion)
    indice0 + 1
  else
    indice0

---
{
  office_id: e.office_id as Number,
  temperatura_actual: tempFinal,
  iluminacion_actual: lightFinal,
  hvac_mode: hvacMode,
  hvac_target: hvacTarget,
  light_mode: lightMode,
  light_target: lightTarget,
  ciclos_estables: ciclosFinal,
  indice_perturbacion: indiceFinal
}
